const j = $json;

const execution = j.execution || {};
const workflow = j.workflow || {};
const error = execution.error || j.error || {};
const node = error.node || {};

const executionId = execution.id ? String(execution.id) : 'unknown';

const workflowName =
  workflow.name ||
  'unknown';

const workflowId =
  workflow.id ||
  null;

const nodeName =
  node.name ||
  execution.lastNodeExecuted ||
  'unknown';

const nodeType =
  node.type ||
  null;

const errorText =
  error.message ||
  error.description ||
  error.name ||
  'unknown';

const executionUrl =
  execution.url ||
  null;

return [{
  json: {
    execution_id: executionId,
    workflow_id: workflowId,
    workflow_name: workflowName,
    node_name: nodeName,
    node_type: nodeType,
    stage: 'workflow_error',
    status: 'error',
    details:
      'Workflow error in node: ' +
      nodeName +
      (executionUrl ? '\nExecution URL: ' + executionUrl : ''),
    error_text: errorText,
    attempt: 1
  }
}];

const ctx = $('Normalize error event').first().json;

return [{
  json: {
    ...ctx,
    error_logged: true
  }
}];
